SELECT count(*) FROM hm_query.disputes_flat

    AND order_id = #{orderId}
    AND state_id = #{stateId}
    AND priority = #{priority}
    AND dispute_type = #{disputeType}
    AND assigned_to = #{assignedTo}
    AND customer_id = #{customerId}
    AND seller_id = #{sellerId}
    AND (
        order_id LIKE CONCAT('%', #{q}, '%')
        OR customer_name LIKE CONCAT('%', #{q}, '%')
        OR seller_name LIKE CONCAT('%', #{q}, '%')
        OR reason LIKE CONCAT('%', #{q}, '%')
        OR order_number LIKE CONCAT('%', #{q}, '%')
    )

SELECT id, order_id as "orderId", order_number as "orderNumber", customer_id as "customerId", customer_name as "customerName", seller_id as "sellerId", seller_name as "sellerName", dispute_type as "disputeType", reason, disputed_amount as "disputedAmount", priority, assigned_to as "assignedTo", state_id as "stateId", flow_id as "flowId", resolution_outcome as "resolution", created_time as "createdAt" FROM hm_query.disputes_flat
AND order_id = #{orderId} AND state_id = #{stateId} AND priority = #{priority} AND dispute_type = #{disputeType} AND assigned_to = #{assignedTo} AND customer_id = #{customerId} AND seller_id = #{sellerId} AND ( order_id LIKE CONCAT('%', #{q}, '%') OR customer_name LIKE CONCAT('%', #{q}, '%') OR seller_name LIKE CONCAT('%', #{q}, '%') OR reason LIKE CONCAT('%', #{q}, '%') OR order_number LIKE CONCAT('%', #{q}, '%') )
${orderby} ${pagination}

SELECT count(*) FROM hm_query.disputes_flat
WHERE priority = #{priority}
AND state_id = #{stateId}

SELECT count(*) FROM hm_query.disputes_flat
WHERE state_id NOT IN ('RESOLVED', 'CLOSED', 'WITHDRAWN')
AND assigned_to = #{assignedTo}
